// Validate inbound payload + generate seeded comparison quotes.
// Body: { vertical, form_data, source_domain?, contact? }
//   vertical: 'auto' | 'home' | 'tenant' | 'travel'
//   form_data: vertical-specific fields
//   contact: { name?, email?, phone?, postal_code? } — optional at this stage
//
// Phase 1 uses seeded carrier list + deterministic price formulas. Phase 3
// replaces this with live insurer rate APIs (Aviva, Intact, etc.). The shape
// returned to the frontend is identical either way, so the swap is invisible.
const body = $input.item.json.body || {};
const headers = $input.item.json.headers || {};
const vertical = String(body.vertical || '').toLowerCase().trim();
const formData = body.form_data || {};
const contact = body.contact || {};
const sourceDomain = String(body.source_domain || headers['origin'] || 'insurance.crystallux.org').replace(/^https?:\/\//, '').replace(/\/$/, '');

const allowedVerticals = ['auto', 'home', 'tenant', 'travel'];
if (allowedVerticals.indexOf(vertical) === -1) {
  return { json: { _empty: true, status: 400, error: 'vertical must be one of: ' + allowedVerticals.join(', ') } };
}

// Seeded carriers per vertical — generic Canadian-sounding names. Each has a
// base monthly premium + a multiplier to produce a believable spread across
// the comparison. Mary can later swap these for real carrier partners by
// inserting rows into insurance_carriers + replacing the seed list.
const CARRIERS = {
  auto: [
    { name: 'BlueLine Auto',        base: 142, mult: 0.92, features: ['Accident forgiveness', '24/7 claims', 'Multi-vehicle discount'] },
    { name: 'Maple Auto Insurance', base: 156, mult: 1.00, features: ['Standard coverage', 'Roadside assistance', 'New driver friendly'] },
    { name: 'Northshield Mutual',   base: 168, mult: 1.04, features: ['Lifetime renewal', 'Glass coverage included', 'Claims-free discount'] },
    { name: 'Polaris Drivers',      base: 174, mult: 1.10, features: ['Premium coverage', 'Rental car included', 'Forgiveness on 1st claim'] },
    { name: 'Heritage Vehicle Care',base: 188, mult: 1.18, features: ['White-glove claims', 'Concierge service', 'Pristine record reward'] }
  ],
  home: [
    { name: 'Foundation Home',      base: 78,  mult: 0.92, features: ['Replacement cost coverage', 'Water damage included', '$1M liability'] },
    { name: 'Maple Home Group',     base: 88,  mult: 1.00, features: ['Standard dwelling cover', 'Personal property protection', 'Identity theft included'] },
    { name: 'Heritage Roof Insurance', base: 96, mult: 1.06, features: ['Guaranteed replacement', 'Sewer backup', 'Earthquake rider available'] },
    { name: 'Northshield Home',     base: 104, mult: 1.12, features: ['High-value home option', '$2M liability', 'All-perils coverage'] },
    { name: 'BlueLine Property',    base: 116, mult: 1.20, features: ['Premium tier', 'Scheduled valuables', 'Loss-of-use included'] }
  ],
  tenant: [
    { name: 'Anchor Renter Cover',  base: 22,  mult: 0.85, features: ['Contents up to $30K', 'Personal liability $1M', 'Theft protection'] },
    { name: 'Maple Renter Group',   base: 28,  mult: 1.00, features: ['Contents up to $60K', '$1M liability', 'Roommate add-on'] },
    { name: 'BlueLine Renters',     base: 32,  mult: 1.08, features: ['Replacement cost', 'Identity theft', 'Sewer backup'] },
    { name: 'Polaris Renters',      base: 35,  mult: 1.15, features: ['High-value contents tier', '$2M liability', 'Loss-of-use'] },
    { name: 'Heritage Tenant',      base: 39,  mult: 1.22, features: ['Concierge claims', 'Scheduled valuables', 'Premium service'] }
  ],
  travel: [
    { name: 'Maple Travel Cover',     base: 58,  mult: 0.88, features: ['$5M emergency medical', 'Trip cancellation $5K', '10-day stability period'] },
    { name: 'Northern Voyage Insurance', base: 72, mult: 1.00, features: ['$10M emergency medical', 'Trip cancellation $7.5K', 'Baggage cover $1500'] },
    { name: 'BlueLine Trip',          base: 84,  mult: 1.10, features: ['Comprehensive coverage', 'Sports rider included', 'Pre-existing 90-day stability'] },
    { name: 'Polaris Traveler',       base: 96,  mult: 1.20, features: ['Premium medical', 'Trip interruption $10K', 'Concierge claims'] },
    { name: 'Heritage Voyager',       base: 108, mult: 1.32, features: ['Highest-tier coverage', 'No annual cap', 'White-glove service'] }
  ]
};

// Vertical-specific factor functions. All return a number between 0.5-2.5 ish
// that multiplies the carrier base. Same input -> same output (deterministic).
function autoFactors(f) {
  const age = parseInt(f.driver_age, 10) || 35;
  const vehicleYear = parseInt(f.vehicle_year, 10) || (new Date().getFullYear() - 5);
  const vehicleAge = Math.max(0, new Date().getFullYear() - vehicleYear);
  const claims = parseInt(f.claims_count, 10) || 0;
  const tickets = parseInt(f.tickets_count, 10) || 0;
  const postal = String(f.postal_code || '').toUpperCase().slice(0, 1);
  const coverage = String(f.coverage_level || 'standard').toLowerCase();

  let m = 1.0;
  if (age < 25)      m *= 1.55;
  else if (age < 30) m *= 1.22;
  else if (age < 50) m *= 1.00;
  else if (age < 65) m *= 0.90;
  else               m *= 1.12;

  if (vehicleAge <= 3)      m *= 1.32;
  else if (vehicleAge <= 7) m *= 1.05;
  else if (vehicleAge <= 12)m *= 0.92;
  else                      m *= 0.82;

  m *= (1 + claims * 0.42);
  m *= (1 + tickets * 0.28);

  const postalMap = { M: 1.18, L: 1.08, K: 1.00, N: 0.96, H: 1.15, V: 1.10, T: 1.02, B: 1.00, R: 0.98, S: 0.96, E: 0.97, J: 1.10 };
  m *= (postalMap[postal] || 1.00);

  if (coverage === 'basic')          m *= 0.82;
  else if (coverage === 'standard')  m *= 1.00;
  else if (coverage === 'comprehensive') m *= 1.28;
  else if (coverage === 'premium')   m *= 1.45;
  return m;
}

function homeFactors(f) {
  const homeValue = parseInt(f.home_value, 10) || 600000;
  const dwellingType = String(f.dwelling_type || 'detached').toLowerCase();
  const claims = parseInt(f.claims_count, 10) || 0;
  const postal = String(f.postal_code || '').toUpperCase().slice(0, 1);
  const yearBuilt = parseInt(f.year_built, 10) || 1990;
  const homeAge = Math.max(0, new Date().getFullYear() - yearBuilt);

  let m = 1.0;
  m *= Math.max(0.55, Math.min(2.4, homeValue / 600000));

  const dwellMap = { detached: 1.0, semi: 0.92, townhouse: 0.88, condo: 0.65, mobile: 0.78 };
  m *= (dwellMap[dwellingType] || 1.0);

  m *= (1 + claims * 0.38);

  if (homeAge > 50)      m *= 1.18;
  else if (homeAge > 30) m *= 1.08;
  else if (homeAge < 5)  m *= 0.92;

  const postalMap = { M: 1.20, L: 1.05, K: 1.00, N: 0.95, H: 1.18, V: 1.15, T: 1.02, B: 1.00, R: 0.97, S: 0.95 };
  m *= (postalMap[postal] || 1.00);
  return m;
}

function tenantFactors(f) {
  const contents = parseInt(f.contents_value, 10) || 30000;
  const claims = parseInt(f.claims_count, 10) || 0;
  const postal = String(f.postal_code || '').toUpperCase().slice(0, 1);
  const roommates = parseInt(f.roommate_count, 10) || 0;

  let m = 1.0;
  m *= Math.max(0.6, Math.min(2.2, contents / 30000));
  m *= (1 + claims * 0.35);
  m *= (1 + roommates * 0.12);

  const postalMap = { M: 1.22, L: 1.06, K: 1.00, N: 0.96, H: 1.18, V: 1.16, T: 1.04 };
  m *= (postalMap[postal] || 1.00);
  return m;
}

function travelFactors(f) {
  const age = parseInt(f.traveler_age, 10) || 40;
  const tripDays = parseInt(f.trip_days, 10) || 14;
  const destRegion = String(f.destination_region || 'usa').toLowerCase();
  const coverageAmount = parseInt(f.coverage_amount, 10) || 5000000;
  const preExisting = String(f.pre_existing || 'none').toLowerCase();

  let m = 1.0;
  if (age < 35)      m *= 0.85;
  else if (age < 55) m *= 1.00;
  else if (age < 65) m *= 1.45;
  else if (age < 75) m *= 2.05;
  else               m *= 2.85;

  m *= Math.max(0.6, Math.min(3.5, tripDays / 14));

  const regionMap = { usa: 1.0, mexico: 0.92, caribbean: 0.95, europe: 0.78, asia: 0.85, worldwide: 1.05 };
  m *= (regionMap[destRegion] || 1.0);

  if (coverageAmount >= 10000000)     m *= 1.22;
  else if (coverageAmount >= 5000000) m *= 1.00;
  else                                 m *= 0.85;

  if (preExisting === 'stable')       m *= 1.12;
  else if (preExisting === 'unstable') m *= 1.85;
  return m;
}

const factorFn = { auto: autoFactors, home: homeFactors, tenant: tenantFactors, travel: travelFactors }[vertical];
const factor = factorFn(formData);

const seedCarriers = CARRIERS[vertical];
const rawQuotes = seedCarriers.map(function (c) {
  const monthly = Math.round(c.base * c.mult * factor * 100) / 100;
  const annual = Math.round(monthly * 12 * 100) / 100;
  return {
    carrier_name: c.name,
    estimated_premium_monthly: monthly,
    estimated_premium_annual:  annual,
    coverage_summary: {
      coverage_level: String(formData.coverage_level || formData.coverage_amount || 'standard'),
      key_features:   c.features
    }
  };
});

// Sort cheapest -> most expensive, rank + flag lowest
rawQuotes.sort(function (a, b) { return a.estimated_premium_monthly - b.estimated_premium_monthly; });
const quotes = rawQuotes.map(function (q, i) {
  return Object.assign({}, q, { rank_position: i + 1, is_lowest: i === 0 });
});

// Build the lead row (insert even if no email — anonymous quote viewer)
const leadRow = {
  full_name:         String(contact.name || '').trim().slice(0, 200) || 'Anonymous quote viewer',
  email:             String(contact.email || '').trim().toLowerCase().slice(0, 200) || null,
  phone:             String(contact.phone || '').trim().slice(0, 40) || null,
  city:              String(contact.city || '').trim().slice(0, 120) || null,
  province:          String(contact.province || formData.province || '').trim().slice(0, 20) || null,
  industry:          'insurance',
  product_type:      vertical + '_insurance',
  lead_type:         'b2c_consumer',
  source:            'marketplace_' + vertical,
  source_domain:     sourceDomain,
  marketplace_vertical: vertical,
  marketplace_status:   'quote_viewed',
  lead_status:       'New Lead',
  lead_score:        45,
  do_not_contact:    false,
  unsubscribed:      false,
  total_emails_sent: 0,
  notes:             'Marketplace ' + vertical + ' quote on ' + new Date().toISOString().slice(0, 10) + ' (source: ' + sourceDomain + '). Form data: ' + JSON.stringify(formData).slice(0, 800)
};

return { json: { vertical: vertical, sourceDomain: sourceDomain, leadRow: leadRow, quotes: quotes, formDataKeys: Object.keys(formData) } };

// Pull the inserted lead id, then build the marketplace_quotes batch insert payload.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const leadRows = allOf('Insert Lead');
const leadId = leadRows.length > 0 ? leadRows[0].id : null;
if (!leadId) {
  return { json: { _failed: true, status: 500, error: 'Lead insert returned no row — check Supabase RLS / service role' } };
}

const v = $('Validate + Build Quotes').item.json;
const quotes = v.quotes.map(function (q) {
  return Object.assign({}, q, {
    lead_id:        leadId,
    source_domain:  v.sourceDomain,
    vertical:       v.vertical
  });
});
return { json: { lead_id: leadId, vertical: v.vertical, quoteRows: quotes } };

// Shape the final response for the frontend. The frontend uses lead_id +
// quote_id to wire up the 'Get this quote' click to the quote-select workflow.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const quotes = allOf('Insert Quotes');
const built = $('Build Quote Rows').item.json;
if (!quotes.length) {
  return { json: { ok: false, status: 500, error: 'No quotes were persisted — check marketplace_quotes RLS or service role' } };
}
return { json: {
  ok: true,
  lead_id: built.lead_id,
  vertical: built.vertical,
  quotes: quotes.map(function (q) {
    return {
      id: q.id,
      carrier_name: q.carrier_name,
      estimated_premium_monthly: parseFloat(q.estimated_premium_monthly),
      estimated_premium_annual:  parseFloat(q.estimated_premium_annual),
      coverage_summary: q.coverage_summary,
      is_lowest: q.is_lowest,
      rank_position: q.rank_position,
      estimate_disclaimer: q.estimate_disclaimer
    };
  }).sort(function (a, b) { return a.rank_position - b.rank_position; })
} };
